import Swiper from 'swiper';
import 'swiper/css';
import 'swiper/css/pagination';
import { Navigation, Pagination } from 'swiper/modules';
import raterFunction from 'rater-js';

import { getFeedbacks } from './services/api.js';
const swiperWrapperEl = document.querySelector('.reviews-swiper .swiper-wrapper');
// document.addEventListener('DOMContentLoaded', initReviewsSection);
initReviewsSection();
async function initReviewsSection() {
  try {
    const { feedbacks } = await getFeedbacks();
    renderMarkup(feedbacks.slice(0, 10));
    initSwiper();
  } catch (error) {
    console.log(error);
  }
}
function renderMarkup(reviews) {
  if (!swiperWrapperEl) return;
  const markup = reviews
    .map(
      ({ rate, description, author }) => `
    <div class="swiper-slide review-card">
    <div id="rater" data-rate="${rate}"></div>
    <p class="review-paragraph">${description}</p>
    <p class="review-author">${author}</p>
    </div> `
    )
    .join('');
  swiperWrapperEl.innerHTML = markup;
  initRating();
}
function initSwiper() {
  const swiper = new Swiper('.reviews-swiper', {
    modules: [Navigation, Pagination],
    slidesPerView: 1,
    breakpoints: {
      768: {
        slidesPerView: 'auto',
      },
    },
    spaceBetween: 24,
    navigation: {
      nextEl: '.reviews-prev',
      prevEl: '.reviews-next',
    },
    pagination: {
      el: '.swiper-pagination',
      type: 'bullets',
      clickable: true,
    },
    mousewheel: true,
    keyboard: true,
  });
}
function initRating() {
  const ratings = document.querySelectorAll('#rater');
  ratings.forEach(el => {
    raterFunction({
      element: el,
      rating: Number(el.dataset.rate) || 0,
      readOnly: true,
      starSize: 20,
      step: 0.5,
    });
  });
}
